arguments.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_cd5404665d8c4b2c8583c65f69e29930.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep" OnNavigate="GoToStep" />

    @switch (_currentStep)
    {
        case 1:
            <PersonalInfoStep Model="_personalInfo"
                              OnNext="NextStep"
                              ValidateEmail="ApplicationService.ValidateEmailAsync" />
            break;
        case 2:
            <WorkHistoryStep Entries="_workEntries"
                             OnNext="NextStep"
                             OnBack="PrevStep" />
            break;
        case 3:
            <ReferencesStep References="_references"
                            OnNext="NextStep"
                            OnBack="PrevStep" />
            break;
        case 4:
            <CoverLetterStep @bind-CoverLetter="_coverLetter"
                             OnNext="NextStep"
                             OnBack="PrevStep" />
            break;
        case 5:
            <ReviewStep Personal="_personalInfo"
                        WorkEntries="_workEntries"
                        References="_references"
                        CoverLetter="@_coverLetter"
                        OnBack="PrevStep"
                        OnEdit="GoToStep"
                        OnSubmit="SubmitAsync" />
            break;
    }
</div>

@code {
    private int _currentStep = 1;
    private readonly PersonalInfoModel _personalInfo = new();
    private readonly List<WorkEntryModel> _workEntries = [new()];
    private readonly List<ReferenceModel> _references = [new(), new()];
    private string _coverLetter = "";

    private void NextStep() => _currentStep = Math.Min(_currentStep + 1, 5);
    private void PrevStep() => _currentStep = Math.Max(_currentStep - 1, 1);
    private void GoToStep(int step) => _currentStep = step;

    private async Task<int> SubmitAsync()
    {
        var application = new JobApplication(
            _personalInfo.ToRecord(),
            new WorkHistory(_workEntries.Select(e => e.ToRecord()).ToList()),
            _references.Select(r => r.ToRecord()).ToList(),
            _coverLetter);

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

::deep .step-indicator .step-circle {
    width: 36px;
    height: 36px;
    font-size: 0.9rem;
    font-weight: 600;
    transition: all 0.2s ease;
}

::deep .step-indicator .step-item.completed {
    cursor: pointer;
}

::deep .step-indicator .step-item.future {
    opacity: 0.5;
    cursor: default;
}

::deep .step-indicator .step-item.active .step-circle {
    box-shadow: 0 0 0 3px rgba(13, 110, 253, 0.25);
}

::deep .last-child-no-border:last-child {
    border-bottom: none !important;
    margin-bottom: 0 !important;
    padding-bottom: 0 !important;
}

